module top_module(
    input clk,
    input rst,
    input [15:0] in_data,
    output [15:0] out_data
);reg [15:0] inverted_data;

always @(posedge clk) begin
    if (rst) begin
        inverted_data <= 0;
    end else begin
        inverted_data <= ~in_data;
    end
end

assign out_data = inverted_data;

endmodule
